/**
 * Priority-based notification routing.
 *
 * Maps notification priority levels to delivery channels:
 * - urgent → sms
 * - normal → email
 * - low → webhook
 */

import type { NotificationChannel, NotificationPriority } from '../events/event-types.js';

const PRIORITY_CHANNEL_MAP: Record<NotificationPriority, NotificationChannel> = {
  urgent: 'sms',
  normal: 'email',
  low: 'webhook',
};

export class PriorityRouterService {
  /**
   * Resolve the delivery channel for a given priority.
   */
  resolve(priority: NotificationPriority): NotificationChannel {
    return PRIORITY_CHANNEL_MAP[priority];
  }
}

/**
 * Audit logging service — records every notification dispatched.
 *
 * Listens for notification:dispatched events on the EventBus and
 * stores an immutable audit trail of all notification deliveries.
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationDispatchedEvent, NotificationChannel, NotificationPriority } from '../events/event-types.js';

export interface AuditEntry {
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  priority: NotificationPriority;
  subject: string;
  timestamp: Date;
  recordedAt: Date;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationDispatchedEvent>('notification:dispatched', (event) => {
      this.record(event);
    });
  }

  private record(event: NotificationDispatchedEvent): void {
    this.entries.push({
      notificationId: event.notificationId,
      recipient: event.recipient,
      channel: event.channel,
      priority: event.priority,
      subject: event.subject,
      timestamp: event.timestamp,
      recordedAt: new Date(),
    });
  }

  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  getEntriesForRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntriesByChannel(channel: NotificationChannel): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service — per-user channel overrides.
 *
 * Allows users to override the default priority-based channel routing.
 * For example, a user may prefer all notifications via email regardless
 * of priority, or want urgent notifications via webhook instead of SMS.
 */

import type { NotificationChannel, NotificationPriority } from '../events/event-types.js';

export interface UserChannelPreference {
  userId: string;
  priority: NotificationPriority;
  channel: NotificationChannel;
}

export class NotificationPreferencesService {
  private preferences: Map<string, Map<NotificationPriority, NotificationChannel>> = new Map();

  /**
   * Set a user's preferred channel for a given priority level.
   */
  setPreference(userId: string, priority: NotificationPriority, channel: NotificationChannel): void {
    if (!this.preferences.has(userId)) {
      this.preferences.set(userId, new Map());
    }
    this.preferences.get(userId)!.set(priority, channel);
  }

  /**
   * Remove a user's preference for a given priority level,
   * falling back to the default priority router.
   */
  removePreference(userId: string, priority: NotificationPriority): void {
    this.preferences.get(userId)?.delete(priority);
  }

  /**
   * Get the user's preferred channel for a priority, or undefined
   * if no override is set (meaning the priority router default applies).
   */
  getPreferredChannel(userId: string, priority: NotificationPriority): NotificationChannel | undefined {
    return this.preferences.get(userId)?.get(priority);
  }

  /**
   * Get all preferences for a user.
   */
  getPreferences(userId: string): UserChannelPreference[] {
    const userPrefs = this.preferences.get(userId);
    if (!userPrefs) return [];
    return Array.from(userPrefs.entries()).map(([priority, channel]) => ({
      userId,
      priority,
      channel,
    }));
  }

  /**
   * Clear all preferences (useful for testing).
   */
  clear(): void {
    this.preferences.clear();
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * NOTE: This service currently uses TWO different patterns for receiving
 * notifications, which is inconsistent and should be unified:
 *
 * 1. EventBus subscriptions (event-driven) — used for order:created events
 * 2. CallbackRegistry (direct callbacks) — used for order:status-changed events
 *
 * Both approaches work but the mixed usage makes the codebase harder to
 * maintain. A future refactor should pick ONE approach and use it consistently.
 *
 * Depends on:
 * - EventBus (event system) for receiving some events
 * - CallbackRegistry (direct callbacks) for other events
 * - PriorityRouterService for channel selection based on priority
 * - NotificationPreferencesService for per-user channel overrides
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  NotificationPriority,
  NotificationChannel,
} from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';
import type { PriorityRouterService } from './priority-router.service.js';
import type { NotificationPreferencesService } from './notification-preferences.service.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: NotificationPriority;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];

  constructor(
    private eventBus: EventBus,
    private priorityRouter?: PriorityRouterService,
    private preferencesService?: NotificationPreferencesService,
  ) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for notification triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   * Order creation is treated as normal priority.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      recipient: event.user.email,
      userId: event.user.id,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of update.
   * Status changes to 'cancelled' are urgent; 'delivered' is low; others are normal.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const priority = this.inferPriority(event.newStatus);

    this.sendNotification({
      recipient: event.order.userId,
      userId: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority,
    });
  }

  /**
   * Infer notification priority from the new order status.
   */
  private inferPriority(newStatus: string): NotificationPriority {
    if (newStatus === 'cancelled') return 'urgent';
    if (newStatus === 'delivered') return 'low';
    return 'normal';
  }

  /**
   * Resolve the delivery channel for a notification, considering
   * user preferences first, then falling back to priority routing.
   */
  resolveChannel(userId: string | undefined, priority: NotificationPriority): NotificationChannel {
    // Check user preferences first
    if (userId && this.preferencesService) {
      const preferred = this.preferencesService.getPreferredChannel(userId, priority);
      if (preferred) return preferred;
    }

    // Fall back to priority-based routing
    if (this.priorityRouter) {
      return this.priorityRouter.resolve(priority);
    }

    // Default fallback if no router is configured
    return 'email';
  }

  /**
   * Send a notification (in-memory for this demo).
   * Resolves the channel via priority routing + user preferences,
   * then emits a notification:dispatched event for audit logging.
   */
  private sendNotification(params: {
    recipient: string;
    userId?: string;
    subject: string;
    body: string;
    priority: NotificationPriority;
  }): void {
    const channel = this.resolveChannel(params.userId, params.priority);

    const notification: Notification = {
      id: generateNotificationId(),
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      channel,
      priority: params.priority,
      sentAt: new Date(),
    };
    this.notifications.push(notification);
    this.logger.info(
      `Notification sent: ${notification.id} to ${params.recipient} via ${channel} (${params.priority})`,
    );

    // Emit event for audit logging
    this.eventBus.emit({
      type: 'notification:dispatched',
      notificationId: notification.id,
      recipient: params.recipient,
      channel,
      priority: params.priority,
      subject: params.subject,
      timestamp: notification.sentAt,
    });
  }

  /**
   * Send a notification with explicit priority (public API for direct use).
   */
  send(params: {
    recipient: string;
    userId?: string;
    subject: string;
    body: string;
    priority: NotificationPriority;
  }): void {
    this.sendNotification(params);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    service = new NotificationService(eventBus);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send notification on status change', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
    });
  });

  describe('notification management', () => {
    it('should count notifications', () => {
      expect(service.getNotificationCount()).toBe(0);

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear notifications', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });
  });
});

